import React, { useState, useEffect } from 'react';
import GlassCard from './GlassCard';
import { Article } from '../types';
import { getTrendingArticles } from '../api/cms';
import ArticleCard from './articles/ArticleCard';


interface GlobalTrendingProps {
  onSelectArticle: (article: Article) => void;
}

const SkeletonCard: React.FC<{ style?: React.CSSProperties }> = ({ style }) => (
    <GlassCard className="flex flex-col p-6 aspect-square animate-pulse" style={style}>
      <div className="h-6 bg-gray-600/50 rounded w-3/4 mb-4"></div>
      <div className="space-y-2 flex-grow">
        <div className="h-4 bg-gray-600/50 rounded w-full"></div>
        <div className="h-4 bg-gray-600/50 rounded w-5/6"></div>
        <div className="h-4 bg-gray-600/50 rounded w-full"></div>
      </div>
    </GlassCard>
);

const GlobalTrending: React.FC<GlobalTrendingProps> = ({ onSelectArticle }) => {
  const [trendingArticles, setTrendingArticles] = useState<Article[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const fetchTrending = async () => {
      setIsLoading(true);
      setError(null);
      try {
        const articles = await getTrendingArticles();
        setTrendingArticles(articles);
      } catch (err: any) {
        console.error("Failed to fetch trending articles:", err);
        setError("Could not load trending topics. Please try again later.");
      } finally {
        setIsLoading(false);
      }
    };

    fetchTrending();
  }, []);

  return (
    <div className="w-full max-w-7xl mx-auto">
      <div className="text-center mb-10">
        <span className="text-[10px] uppercase tracking-[0.3em] text-red-600 font-bold mb-2 block">Live Intelligence</span>
        <h2 className="text-5xl font-extrabold text-white uppercase">
          GLOBAL <span className="text-red-600">TRENDING</span>
        </h2>
      </div>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 stagger-fade-in-up">
        {isLoading ? (
          Array.from({ length: 3 }).map((_, index) => <SkeletonCard key={index} style={{ transitionDelay: `${index * 100}ms` }} />)
        ) : error ? (
          <div className="col-span-full text-center py-10"><p className="text-red-400">{error}</p></div>
        ) : (
          trendingArticles.map((article, index) => (
            <div key={article.id} className="flex flex-col">
              <span className="text-[10px] uppercase text-red-600 font-bold mb-2 ml-1">Trending Intelligence</span>
              <ArticleCard
                article={article}
                onClick={() => onSelectArticle(article)}
                style={{ transitionDelay: `${index * 100}ms` }}
              />
            </div>
          ))
        )}
      </div>
    </div>
  );
};

export default GlobalTrending;

