import React, { useState, useEffect, useRef } from 'react';
import { Page } from '../types';

interface NavLinkProps {
  page: Page;
  activePage?: Page;
  onNavClick: (page: Page) => void;
  children: React.ReactNode;
  className?: string;
}

const NavLink: React.FC<NavLinkProps> = ({ page, activePage, onNavClick, children, className }) => {
  const handleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault();
    onNavClick(page);
  };

  const isActive = activePage === page;
  const baseClasses = "px-3 py-2 rounded-md text-sm font-medium transition-colors duration-200 uppercase tracking-wider";
  const activeClasses = "bg-white/10 text-white";
  const inactiveClasses = "text-gray-300 hover:text-white hover:bg-white/10";
  const href = page === Page.Home ? '#' : `#${page}`;

  return (
    <a href={href} onClick={handleClick} className={`${baseClasses} ${isActive ? activeClasses : inactiveClasses} ${className || ''}`}>
      {children}
    </a>
  );
};

interface HeaderProps {
    activePage?: Page;
    onNavClick: (page: Page) => void;
    searchQuery: string;
    onSearchChange: (query: string) => void;
}

const Header: React.FC<HeaderProps> = ({ activePage, onNavClick, searchQuery, onSearchChange }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const headerRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 10);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const header = headerRef.current;
    if (!header) return;

    const handleMouseMove = (e: MouseEvent) => {
      const rect = header.getBoundingClientRect();
      const x = e.clientX - rect.left;
      const y = e.clientY - rect.top;
      header.style.setProperty('--mouse-x', `${x}px`);
      header.style.setProperty('--mouse-y', `${y}px`);
    };

    header.addEventListener('mousemove', handleMouseMove);
    return () => header.removeEventListener('mousemove', handleMouseMove);
  }, []);

  const navItems = Object.values(Page).filter(p => p !== 'Author' && p !== 'Article'); 

  return (
    <header 
      ref={headerRef}
      className={`glass-card fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${isScrolled || isMenuOpen || activePage !== Page.Home ? 'bg-black/80 backdrop-blur-lg' : 'bg-transparent'}`}
    >
      <div className="px-4 sm:px-6 md:px-8">
        <div className="flex items-center justify-between h-20">
          <div className="flex-shrink-0">
            <button onClick={() => onNavClick(Page.Home)} className="flex items-center space-x-3" aria-label="Go to Novus Exchange homepage">
              <svg className="h-8 w-8 text-white" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path>
              </svg>
              <div className="text-left">
                <span className="block text-white font-bold text-xl tracking-tight leading-tight">Novus Exchange</span>
                <span className="block text-gray-400 text-[10px] uppercase tracking-widest leading-tight">Connecting perspectives</span>
              </div>
            </button>
          </div>

          <nav className="hidden md:flex items-center space-x-1">
            {navItems.map(page => (
                <NavLink key={page} page={page} activePage={activePage} onNavClick={onNavClick}>{page.replace('-', ' ')}</NavLink>
            ))}
             <div className="relative ml-4">
                <input
                    type="text"
                    placeholder="Search..."
                    value={searchQuery}
                    onChange={(e) => onSearchChange(e.target.value)}
                    className="bg-white/10 border-white/20 rounded-md py-1.5 pl-8 pr-3 text-sm text-white focus:outline-none focus:ring-2 focus:ring-red-500 transition-all duration-300"
                />
                <svg className="absolute left-2 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
            </div>
          </nav>

          <div className="md:hidden">
            <button
              onClick={() => setIsMenuOpen(!isMenuOpen)}
              className="inline-flex items-center justify-center p-2 rounded-md text-gray-400 hover:text-white hover:bg-white/10 focus:outline-none"
            >
              <svg className="h-6 w-6" stroke="currentColor" fill="none" viewBox="0 0 24 24">
                {isMenuOpen ? (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" />
                ) : (
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16M4 18h16" />
                )}
              </svg>
            </button>
          </div>
        </div>
      </div>

      {isMenuOpen && (
        <div className="md:hidden">
          <div className="px-2 pt-2 pb-3 space-y-1 sm:px-3">
            {navItems.map(page => (
                <NavLink key={page} page={page} activePage={activePage} onNavClick={(p) => { onNavClick(p); setIsMenuOpen(false); }} className="block w-full text-left">{page.replace('-', ' ')}</NavLink>
            ))}
             <div className="relative px-3 pt-2">
                <input
                    type="text"
                    placeholder="Search..."
                    value={searchQuery}
                    onChange={(e) => onSearchChange(e.target.value)}
                    className="w-full bg-white/10 border-white/20 rounded-md py-2 pl-8 pr-3 text-sm text-white focus:outline-none focus:ring-2 focus:ring-red-500 transition-all duration-300"
                />
                <svg className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" />
                </svg>
            </div>
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

import React, { useState, useEffect, useRef } from 'react';
import { Page, Article, Author, NovusMessage } from './types';
import { getArticles } from './api/cms';
import { GoogleGenAI } from '@google/genai';

import Layout from './components/layout/Layout';
import Hero from './components/Hero';
import Mission from './components/About';
import Articles from './components/Articles';
import ArticlePage from './components/articles/ArticlePage';
import AuthorPage from './components/author/AuthorPage';
import GlobalTrending from './components/GlobalTrending';
import Ecosystem from './components/Ecosystem';
import Contact from './components/Contact';
import Chatbot from './components/Chatbot';

const App: React.FC = () => {
    const [activePage, setActivePage] = useState<Page>(Page.Home);
    const [selectedArticle, setSelectedArticle] = useState<Article | null>(null);
    const [selectedAuthor, setSelectedAuthor] = useState<Author | null>(null);
    const [searchQuery, setSearchQuery] = useState('');

    const [allArticles, setAllArticles] = useState<Article[]>([]);
    const [articlesLoading, setArticlesLoading] = useState<boolean>(true);
    const [articlesError, setArticlesError] = useState<string | null>(null);
    const [filteredArticles, setFilteredArticles] = useState<Article[]>([]);

    const [isChatbotOpen, setIsChatbotOpen] = useState(false);
    const [messages, setMessages] = useState<NovusMessage[]>([
        { id: 0, source: 'model', text: "Hello! I'm Novus, your AI research assistant. Ask me anything about our articles, global trends, or other complex topics." }
    ]);

    const missionRef = useRef<HTMLElement>(null);
    const articlesRef = useRef<HTMLElement>(null);
    const trendingRef = useRef<HTMLElement>(null);
    const ecosystemRef = useRef<HTMLElement>(null);
    const contactRef = useRef<HTMLElement>(null);

    useEffect(() => {
        const observer = new IntersectionObserver(
            (entries, obs) => {
                entries.forEach((entry) => {
                    if (entry.isIntersecting) {
                        entry.target.classList.add('is-visible');
                        obs.unobserve(entry.target);
                    }
                });
            },
            { rootMargin: '0px', threshold: 0.05 }
        );
        const sections = [missionRef, articlesRef, trendingRef, ecosystemRef, contactRef];
        sections.forEach(ref => { if (ref.current) observer.observe(ref.current); });
        return () => observer.disconnect();
    }, []);

    useEffect(() => {
        const loadArticles = async () => {
            try {
                setArticlesLoading(true);
                const articles = await getArticles();
                setAllArticles(articles);
            } catch (error) {
                console.error("Failed to load articles:", error);
                setArticlesError("Could not load articles.");
            } finally {
                setArticlesLoading(false);
            }
        };
        loadArticles();
    }, []);

    useEffect(() => {
        const lowercasedQuery = searchQuery.toLowerCase().trim();
        if (!lowercasedQuery) {
            setFilteredArticles(allArticles);
            return;
        }
        const results = allArticles.filter(article =>
            article.title.toLowerCase().includes(lowercasedQuery) ||
            article.excerpt.toLowerCase().includes(lowercasedQuery) ||
            article.tags.some(tag => tag.toLowerCase().includes(lowercasedQuery)) ||
            article.author.name.toLowerCase().includes(lowercasedQuery)
        );
        setFilteredArticles(results);
        if (searchQuery) handleNavClick(Page.Articles);
    }, [searchQuery, allArticles]);

    const handleNavClick = (page: Page) => {
        if (activePage === Page.Article || activePage === Page.Author) {
            setActivePage(Page.Home);
            setSelectedArticle(null);
            setSelectedAuthor(null);
        }
        setTimeout(() => {
            if (page === Page.Home) {
                window.scrollTo({ top: 0, behavior: 'smooth' });
            } else {
                const element = document.getElementById(page);
                if (element) {
                    const headerOffset = 80;
                    const elementPosition = element.getBoundingClientRect().top;
                    const offsetPosition = elementPosition + window.pageYOffset - headerOffset;
                    window.scrollTo({ top: offsetPosition, behavior: 'smooth' });
                }
            }
        }, 100);
    };

    const handleSelectArticle = (article: Article) => {
        setActivePage(Page.Article);
        setSelectedArticle(article);
        window.scrollTo(0, 0);
    };

    const handleSelectAuthor = (author: Author) => {
        setActivePage(Page.Author);
        setSelectedAuthor(author);
        window.scrollTo(0, 0);
    };

    const handleBackToHome = () => {
        setActivePage(Page.Home);
        setSelectedArticle(null);
        setSelectedAuthor(null);
    };

    const handleChatbotSendMessage = async (message: string) => {
        const userMessage: NovusMessage = { id: Date.now(), source: 'user', text: message };
        const loadingMessage: NovusMessage = { id: Date.now() + 1, source: 'model', isLoading: true };
        setMessages(prev => [...prev, userMessage, loadingMessage]);
        try {
            const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
            const articlesContext = allArticles.map(article => `Title: ${article.title}\nExcerpt: ${article.excerpt}`).join('\n\n');
            const response = await ai.models.generateContent({
                model: 'gemini-3-flash-preview',
                contents: `Context: ${articlesContext}\nUser: ${message}`,
                config: { systemInstruction: "Answer briefly based on the provided context." }
            });
            const modelResponse: NovusMessage = { id: Date.now() + 2, source: 'model', text: response.text };
            setMessages(prev => [...prev.slice(0, -1), modelResponse]);
        } catch (error: any) {
            setMessages(prev => [...prev.slice(0, -1), { id: Date.now(), source: 'model', text: "Error connecting to AI." }]);
        }
    };

    const renderContent = () => {
        if (activePage === Page.Author && selectedAuthor) {
            const authorArticles = allArticles.filter(a => a.author.id === selectedAuthor.id);
            return <AuthorPage author={selectedAuthor} articles={authorArticles} onBack={handleBackToHome} onSelectArticle={handleSelectArticle} />;
        }
        if (activePage === Page.Article && selectedArticle) {
            return <ArticlePage article={selectedArticle} articles={allArticles} onBack={handleBackToHome} onSelectArticle={handleSelectArticle} onSelectAuthor={handleSelectAuthor} onAskNovusHighlight={() => {}} />;
        }
        const sectionClasses = "min-h-[70vh] scroll-mt-20 flex items-center justify-center px-4 sm:px-6 md:px-8 py-12";
        const contentWrapperClasses = "container mx-auto w-full max-w-7xl";
        return (
            <>
                <section id={Page.Home} className="relative min-h-screen flex items-center justify-center overflow-hidden">
                    <Hero onNavClick={handleNavClick} />
                </section>
                <section id={Page.Mission} ref={missionRef} className={`${sectionClasses} fade-in-section`}>
                    <div className={contentWrapperClasses}><Mission /></div>
                </section>
                <section id={Page.Articles} ref={articlesRef} className={`${sectionClasses} fade-in-parent-only`}>
                    <div className={contentWrapperClasses}>
                        {articlesLoading ? <div className="text-center text-white">Loading...</div> : <Articles articles={filteredArticles.slice(0, 3)} onSelectArticle={handleSelectArticle} showFilters={false} />}
                    </div>
                </section>
                <section id={Page.GlobalTrending} ref={trendingRef} className={`${sectionClasses} fade-in-parent-only`}>
                    <div className={contentWrapperClasses}><GlobalTrending onSelectArticle={handleSelectArticle} /></div>
                </section>
                <section id={Page.Ecosystem} ref={ecosystemRef} className={`${sectionClasses} fade-in-section`}>
                    <div className={contentWrapperClasses}><Ecosystem /></div>
                </section>
                <section id={Page.Contact} ref={contactRef} className={`${sectionClasses} fade-in-section`}>
                    <div className={contentWrapperClasses}><Contact /></div>
                </section>
            </>
        );
    };

    return (
        <div className="bg-black text-gray-100 font-sans selection:bg-red-600 selection:text-white">
            <div className="fixed top-0 left-0 w-full h-full bg-gradient-to-br from-gray-900 via-black to-blue-900/30 z-0 pointer-events-none"></div>
            <Layout activePage={activePage} onNavClick={handleNavClick} searchQuery={searchQuery} onSearchChange={setSearchQuery}>{renderContent()}</Layout>
            <Chatbot isOpen={isChatbotOpen} setIsOpen={setIsChatbotOpen} messages={messages} onSendMessage={handleChatbotSendMessage} />
        </div>
    );
};

export default App;

