import React, { useState, useEffect, useRef } from 'react';
import { Page } from '../types';

interface NavLinkProps {
  page: Page;
  activePage?: Page;
  onNavClick: (page: Page) => void;
  children: React.ReactNode;
  className?: string;
}

const NavLink: React.FC<NavLinkProps> = ({ page, activePage, onNavClick, children, className }) => {
  const handleClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    e.preventDefault();
    onNavClick(page);
  };
  const isActive = activePage === page;
  const baseClasses = "px-3 py-2 rounded text-[10px] font-bold transition-all duration-200 uppercase tracking-[0.2em]";
  const activeClasses = "text-white bg-white/5";
  const inactiveClasses = "text-gray-400 hover:text-white";
  const href = page === Page.Home ? '#' : `#${page}`;
  return (
    <a href={href} onClick={handleClick} className={`${baseClasses} ${isActive ? activeClasses : inactiveClasses} ${className || ''}`}>
      {children}
    </a>
  );
};

interface HeaderProps {
    activePage?: Page;
    onNavClick: (page: Page) => void;
    searchQuery: string;
    onSearchChange: (query: string) => void;
}

const Header: React.FC<HeaderProps> = ({ activePage, onNavClick, searchQuery, onSearchChange }) => {
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isScrolled, setIsScrolled] = useState(false);
  const headerRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = Object.values(Page).filter(p => p !== 'Author' && p !== 'Article'); 

  return (
    <header 
      ref={headerRef}
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 border-b ${isScrolled || isMenuOpen || activePage !== Page.Home ? 'bg-black/80 backdrop-blur-xl border-white/10 py-3' : 'bg-transparent border-transparent py-5'}`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between">
          <button onClick={() => onNavClick(Page.Home)} className="flex items-center space-x-3 group" aria-label="Logo">
            <svg className="h-6 w-6 text-white group-hover:scale-110 transition-transform" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5">
              <path d="M12 2L2 7l10 5 10-5-10-5zM2 17l10 5 10-5M2 12l10 5 10-5"></path>
            </svg>
            <div className="text-left">
              <span className="block text-white font-black text-lg tracking-tighter leading-none uppercase">Novus Exchange</span>
            </div>
          </button>

          <nav className="hidden md:flex items-center space-x-2">
            {navItems.map(page => (
                <NavLink key={page} page={page} activePage={activePage} onNavClick={onNavClick}>{page.replace('-', ' ')}</NavLink>
            ))}
            <div className="relative ml-4">
                <input
                    type="text"
                    placeholder="SEARCH..."
                    value={searchQuery}
                    onChange={(e) => onSearchChange(e.target.value)}
                    className="bg-white/5 border border-white/10 rounded py-1 px-8 text-[10px] font-bold text-white focus:outline-none focus:border-red-500/50 transition-all w-32 focus:w-48 placeholder:text-gray-600"
                />
                <svg className="absolute left-2.5 top-1/2 -translate-y-1/2 w-3 h-3 text-gray-500" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
            </div>
          </nav>

          <button onClick={() => setIsMenuOpen(!isMenuOpen)} className="md:hidden p-2 text-gray-400 hover:text-white">
            <svg className="h-6 w-6" stroke="currentColor" fill="none" viewBox="0 0 24 24">
              {isMenuOpen ? <path d="M6 18L18 6M6 6l12 12" /> : <path d="M4 6h16M4 12h16M4 18h16" />}
            </svg>
          </button>
        </div>
      </div>

      {isMenuOpen && (
        <div className="md:hidden bg-black/95 border-b border-white/10 animate-fade-in-down">
          <div className="px-4 py-6 space-y-4">
            {navItems.map(page => (
                <NavLink key={page} page={page} activePage={activePage} onNavClick={(p) => { onNavClick(p); setIsMenuOpen(false); }} className="block py-4 border-b border-white/5">{page.replace('-', ' ')}</NavLink>
            ))}
          </div>
        </div>
      )}
    </header>
  );
};

export default Header;

